import React, { useState } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';
import PERatioGraph from '../components/PERatioGraph';
import KMeansClusteringGraph from '../components/KMeansClusteringGraph';
import CombinedKMeansClustering from '../components/CombinedKMeansClustering';

const PortfolioContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
`;

const PageTitle = styled(motion.h1)`
  font-size: 2.5rem;
  margin-bottom: 2rem;
  text-align: center;
  background: linear-gradient(45deg, #00b894, #00cec9);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
`;

const PortfolioGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 2rem;
  margin-top: 2rem;
`;

const PortfolioCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 1.5rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;
  cursor: pointer;

  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
  }
`;

const ExpandedCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  margin-bottom: 2rem;
`;

const CloseButton = styled.button`
  background: rgba(255, 107, 107, 0.2);
  border: 1px solid rgba(255, 107, 107, 0.5);
  color: #ff6b6b;
  padding: 0.5rem 0.8rem;
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;
  float: right;

  &:hover {
    background: rgba(255, 107, 107, 0.4);
    transform: scale(1.05);
  }
`;

const PortfolioHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
`;

const PortfolioName = styled.div`
  display: flex;
  flex-direction: column;
`;

const StockName = styled.h3`
  font-size: 1.3rem;
  color: #ffffff;
  margin: 0;
`;

const StockSymbol = styled.p`
  font-size: 0.9rem;
  color: #cccccc;
  margin: 0;
`;

const RemoveButton = styled.button`
  background: rgba(255, 107, 107, 0.2);
  border: 1px solid rgba(255, 107, 107, 0.5);
  color: #ff6b6b;
  padding: 0.5rem 0.8rem;
  border-radius: 5px;
  cursor: pointer;
  font-weight: 600;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 107, 107, 0.4);
    transform: scale(1.05);
  }
`;

const PortfolioValue = styled.div`
  font-size: 1.8rem;
  font-weight: bold;
  color: #00b894;
  margin-bottom: 0.5rem;
`;

const PortfolioChange = styled.div<{ positive: boolean }>`
  color: ${props => props.positive ? '#00b894' : '#ff6b6b'};
  font-size: 1.1rem;
  margin-bottom: 1rem;
`;

const PortfolioStats = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-top: 1rem;
`;

const StatItem = styled.div`
  text-align: center;
  padding: 0.5rem;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 8px;
`;

const StatLabel = styled.div`
  font-size: 0.8rem;
  color: #cccccc;
  margin-bottom: 0.2rem;
`;

const StatValue = styled.div`
  font-size: 1.1rem;
  font-weight: bold;
  color: #ffffff;
`;

const EmptyState = styled(motion.div)`
  text-align: center;
  padding: 4rem 2rem;
  color: #cccccc;
`;

const EmptyText = styled.p`
  font-size: 1.2rem;
  margin-bottom: 1rem;
`;

const AnalyticsCard = styled(motion.div)`
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 15px;
  padding: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
  margin-bottom: 3rem;
  transition: all 0.3s ease;

  &:hover {
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
    border-color: rgba(255, 255, 255, 0.2);
  }
`;

const Portfolio: React.FC = () => {
  const { user, portfolio, removeFromPortfolio } = useAuth();
  const [expandedSymbol, setExpandedSymbol] = useState<string | null>(null);

  const totalValue = portfolio.reduce((total, item) => {
    return total + item.price;
  }, 0);

  const totalChange = portfolio.reduce((total, item) => {
    return total + item.change;
  }, 0);

  const avgChange = portfolio.length > 0 ? (totalChange / portfolio.length).toFixed(2) : '0.00';
  const isPositive = parseFloat(avgChange) >= 0;

  return (
    <PortfolioContainer>
      <PageTitle
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        💼 My Portfolio
      </PageTitle>

      <motion.div
        style={{ textAlign: 'center', marginBottom: '2rem' }}
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.2 }}
      >
        {user && (
          <p style={{ color: '#cccccc', marginBottom: '0.5rem' }}>
            Hello, {user.first_name || user.username}!
          </p>
        )}
        <h2 style={{ color: '#00b894', fontSize: '2rem', marginBottom: '0.5rem' }}>
          Total Value: ${totalValue.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
        </h2>
        <p style={{ color: avgChange && isPositive ? '#00b894' : '#ff6b6b' }}>
          Average Change: {avgChange}% {isPositive ? '📈' : '📉'}
        </p>
      </motion.div>

      {portfolio.length === 0 ? (
        <EmptyState
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.3 }}
        >
          <EmptyText>📊 Your portfolio is empty</EmptyText>
          <p>Click the "Add" button on any stock to add it to your portfolio</p>
        </EmptyState>
      ) : (
        <>
          {/* Expanded Card View */}
          {expandedSymbol && (
            <>
              {portfolio
                .filter(item => item.symbol === expandedSymbol)
                .map(item => (
                  <ExpandedCard
                    key={item.symbol}
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.3 }}
                  >
                    <CloseButton onClick={() => setExpandedSymbol(null)}>
                      ✕ Close
                    </CloseButton>
                    <div style={{ clear: 'both', marginBottom: '1rem' }}>
                      <StockName>{item.name}</StockName>
                      <StockSymbol>{item.symbol}</StockSymbol>
                    </div>

                    <PortfolioValue>
                      ${item.price.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </PortfolioValue>
                    <PortfolioChange positive={item.change >= 0}>
                      {item.change >= 0 ? '+' : ''}{item.change.toFixed(2)}% {item.change >= 0 ? '📈' : '📉'}
                    </PortfolioChange>

                    {/* Charts Section */}
                    <div style={{ marginTop: '2rem', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '1rem' }}>
                      <PERatioGraph stockSymbol={item.symbol} stockPrice={item.price} />
                      <KMeansClusteringGraph 
                        stockSymbol={item.symbol}
                        stockPrice={item.price}
                        stockName={item.name}
                      />
                    </div>

                    <div style={{ marginTop: '2rem' }}>
                      <RemoveButton onClick={() => {
                        removeFromPortfolio(item.symbol);
                        setExpandedSymbol(null);
                      }}>
                        Remove from Portfolio
                      </RemoveButton>
                    </div>
                  </ExpandedCard>
                ))}
            </>
          )}

          {/* Grid View */}
          <PortfolioGrid>
            {portfolio.map((item, index) => (
              <PortfolioCard
                key={item.symbol}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                whileHover={{ scale: 1.02 }}
                onClick={() => setExpandedSymbol(item.symbol)}
              >
                <PortfolioHeader>
                  <PortfolioName>
                    <StockName>{item.name}</StockName>
                    <StockSymbol>{item.symbol}</StockSymbol>
                  </PortfolioName>
                  <RemoveButton 
                    onClick={(e) => {
                      e.stopPropagation();
                      removeFromPortfolio(item.symbol);
                    }}
                  >
                    ✕
                  </RemoveButton>
                </PortfolioHeader>

                <PortfolioValue>
                  ${item.price.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </PortfolioValue>
                <PortfolioChange positive={item.change >= 0}>
                  {item.change >= 0 ? '+' : ''}{item.change.toFixed(2)}% {item.change >= 0 ? '📈' : '📉'}
                </PortfolioChange>

                <PortfolioStats>
                  <StatItem>
                    <StatLabel>Added</StatLabel>
                    <StatValue>{new Date(item.addedAt).toLocaleDateString()}</StatValue>
                  </StatItem>
                  <StatItem>
                    <StatLabel>Change</StatLabel>
                    <StatValue style={{ color: item.change >= 0 ? '#00b894' : '#ff6b6b' }}>
                      {item.change.toFixed(2)}%
                    </StatValue>
                  </StatItem>
                </PortfolioStats>

                <div style={{ marginTop: '1rem', textAlign: 'center', color: '#4ecdc4', fontSize: '0.9rem' }}>
                  Click to view charts 📊
                </div>
              </PortfolioCard>
            ))}
          </PortfolioGrid>
        </>
      )}
    </PortfolioContainer>
  );
};

export default Portfolio;
